/**
 * ErrorMessage Component
 *
 * エラー、警告、情報メッセージを表示するコンポーネント。
 * variant propによってスタイルを切り替えることができます。
 *
 * 使用例:
 * ```tsx
 * <ErrorMessage message="Invalid email address" variant="error" />
 * <ErrorMessage message="Your session will expire soon" variant="warning" />
 * <ErrorMessage message="Password must be 8 characters" variant="info" />
 * ```
 */

import React from 'react';

export interface ErrorMessageProps {
  /** 表示するメッセージ（null/undefined/空文字列の場合は何も表示しない） */
  message?: string | null;
  /** メッセージのバリアント（デフォルト: 'error'） */
  variant?: 'error' | 'warning' | 'info' | 'success';
  /** 追加のCSSクラス名 */
  className?: string;
}

/**
 * ErrorMessageコンポーネント
 * エラー、警告、情報メッセージを表示します
 */
const ErrorMessage: React.FC<ErrorMessageProps> = ({
  message,
  variant = 'error',
  className = '',
}) => {
  // メッセージが空の場合は何も表示しない
  if (!message || message.trim() === '') {
    return null;
  }

  // バリアント別のスタイルクラス
  const variantClasses = {
    error: 'error bg-red-50 text-red-700 border-red-200',
    warning: 'warning bg-yellow-50 text-yellow-700 border-yellow-200',
    info: 'info bg-blue-50 text-blue-700 border-blue-200',
    success: 'success bg-green-50 text-green-700 border-green-200',
  };

  // バリアント別のアイコン
  const icons = {
    error: (
      <svg
        className="w-5 h-5 mr-2 flex-shrink-0"
        fill="currentColor"
        viewBox="0 0 20 20"
        xmlns="http://www.w3.org/2000/svg"
        aria-hidden="true"
      >
        <path
          fillRule="evenodd"
          d="M10 18a8 8 0 100-16 8 8 0 000 16zM8.707 7.293a1 1 0 00-1.414 1.414L8.586 10l-1.293 1.293a1 1 0 101.414 1.414L10 11.414l1.293 1.293a1 1 0 001.414-1.414L11.414 10l1.293-1.293a1 1 0 00-1.414-1.414L10 8.586 8.707 7.293z"
          clipRule="evenodd"
        />
      </svg>
    ),
    warning: (
      <svg
        className="w-5 h-5 mr-2 flex-shrink-0"
        fill="currentColor"
        viewBox="0 0 20 20"
        xmlns="http://www.w3.org/2000/svg"
        aria-hidden="true"
      >
        <path
          fillRule="evenodd"
          d="M8.257 3.099c.765-1.36 2.722-1.36 3.486 0l5.58 9.92c.75 1.334-.213 2.98-1.742 2.98H4.42c-1.53 0-2.493-1.646-1.743-2.98l5.58-9.92zM11 13a1 1 0 11-2 0 1 1 0 012 0zm-1-8a1 1 0 00-1 1v3a1 1 0 002 0V6a1 1 0 00-1-1z"
          clipRule="evenodd"
        />
      </svg>
    ),
    info: (
      <svg
        className="w-5 h-5 mr-2 flex-shrink-0"
        fill="currentColor"
        viewBox="0 0 20 20"
        xmlns="http://www.w3.org/2000/svg"
        aria-hidden="true"
      >
        <path
          fillRule="evenodd"
          d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7-4a1 1 0 11-2 0 1 1 0 012 0zM9 9a1 1 0 000 2v3a1 1 0 001 1h1a1 1 0 100-2v-3a1 1 0 00-1-1H9z"
          clipRule="evenodd"
        />
      </svg>
    ),
    success: (
      <svg
        className="w-5 h-5 mr-2 flex-shrink-0"
        fill="currentColor"
        viewBox="0 0 20 20"
        xmlns="http://www.w3.org/2000/svg"
        aria-hidden="true"
      >
        <path
          fillRule="evenodd"
          d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z"
          clipRule="evenodd"
        />
      </svg>
    ),
  };

  // ARIA role（アクセシビリティ）
  const ariaRole = variant === 'error' ? 'alert' : 'status';

  return (
    <div
      className={`${variantClasses[variant]} flex items-start p-4 mb-4 text-sm border rounded-lg ${className}`}
      role={ariaRole}
      aria-live={variant === 'error' ? 'assertive' : 'polite'}
    >
      {icons[variant]}
      <span className="sr-only">
        {variant === 'error'
          ? 'Error'
          : variant === 'warning'
            ? 'Warning'
            : variant === 'success'
              ? 'Success'
              : 'Info'}
        :
      </span>
      <div className="flex-1">{message}</div>
    </div>
  );
};

export default ErrorMessage;
